import math

def solve(gender, scr, age):
    # Step 1: determine_coefficients_a_and_b
    # Determine the coefficients A and B based on patient's gender and serum creatinine level.
    if gender == 'female':
        if scr <= 0.7:
            coefficient_a = 0.7
            coefficient_b = -0.241
        else:
            coefficient_a = 0.7
            coefficient_b = -1.2
    elif gender == 'male':
        if scr <= 0.9:
            coefficient_a = 0.9
            coefficient_b = -0.302
        else:
            coefficient_a = 0.9
            coefficient_b = -1.2
    yield {
        "step_name": "determine_coefficients_a_and_b",
        "step_description": "Determine the coefficients A and B based on patient's gender and serum creatinine level.",
        "step_result": {"coefficient_a": coefficient_a, "coefficient_b": coefficient_b},
        "unit": None
    }

    # Step 2: select_gender_coefficient
    # Select the gender coefficient based on patient's gender.
    if gender == 'female':
        gender_coefficient = 1.012
    else:
        gender_coefficient = 1.0
    yield {
        "step_name": "select_gender_coefficient",
        "step_description": "Select the gender coefficient based on patient's gender.",
        "step_result": gender_coefficient,
        "unit": None
    }

    # Step 3: calculate_gfr
    # Calculate the Glomerular Filtration Rate using the 2021 CKD-EPI Creatinine equation.
    gfr = 142 * (scr / coefficient_a) ** coefficient_b * (0.9938 ** age) * gender_coefficient
    gfr = round(gfr, 4)
    yield {
        "step_name": "calculate_gfr",
        "step_description": "Calculate the Glomerular Filtration Rate using the 2021 CKD-EPI Creatinine equation.",
        "step_result": gfr,
        "unit": "mL/min/1.73 m²"
    }

    return gfr
